return [ 'version' => '2.0', 'service' => '<p>Welcome to the Amazon Bedrock AgentCore Control plane API reference. Control plane actions configure, create, modify, and monitor Amazon Web Services resources.</p>', 'operations' => [ 'AddDatasetExamples' => '<p> Adds examples to the dataset\'s DRAFT. All examples are validated against the dataset\'s schema type before any writes occur. If any example fails validation, the entire batch is rejected (all-or-nothing semantics). </p>', 'CreateAgentRuntime' => '<p>Creates an Amazon Bedrock AgentCore Runtime.</p>', 'CreateAgentRuntimeEndpoint' => '<p>Creates an AgentCore Runtime endpoint.</p>', 'CreateApiKeyCredentialProvider' => '<p>Creates a new API key credential provider.</p>', 'CreateBrowser' => '<p>Creates a custom browser.</p>', 'CreateBrowserProfile' => '<p>Creates a browser profile in Amazon Bedrock AgentCore. A browser profile stores persistent browser data such as cookies, local storage, session storage, and browsing history that can be saved from browser sessions and reused in subsequent sessions.</p>', 'CreateCodeInterpreter' => '<p>Creates a custom code interpreter.</p>', 'CreateConfigurationBundle' => '<p>Creates a new configuration bundle resource. A configuration bundle stores versioned component configurations for agent evaluation workflows.</p>', 'CreateDataset' => '<p> Creates a new dataset resource asynchronously. Returns immediately with status CREATING. Poll <code>GetDataset</code> until status transitions to ACTIVE or CREATE_FAILED. </p>', 'CreateDatasetVersion' => '<p> Publishes the current DRAFT as a new numbered version. The DRAFT is preserved and remains editable after publishing. Returns immediately with status UPDATING. Poll <code>GetDataset</code> until status transitions to ACTIVE or UPDATE_FAILED. </p>', 'CreateEvaluator' => '<p> Creates a custom evaluator for agent quality assessment. Custom evaluators can use either LLM-as-a-Judge configurations with user-defined prompts, rating scales, and model settings, or code-based configurations with customer-managed Lambda functions to evaluate agent performance at tool call, trace, or session levels. </p>', 'CreateGateway' => '<p>Creates a gateway for Amazon Bedrock Agent. A gateway serves as an integration point between your agent and external services.</p> <p>If you specify <code>CUSTOM_JWT</code> as the <code>authorizerType</code>, you must provide an <code>authorizerConfiguration</code>.</p>', 'CreateGatewayRule' => '<p>Creates a rule for a gateway. Rules define conditions and actions that control how requests are routed and processed through the gateway, including principal-based access control and path-based routing.</p>', 'CreateGatewayTarget' => '<p>Creates a target for a gateway. A target defines an endpoint that the gateway can connect to.</p>', 'CreateHarness' => '<p>Operation to create a harness.</p>', 'CreateHarnessEndpoint' => '<p>Operation to create a harness endpoint.</p>', 'CreateMemory' => '<p>Creates a new Amazon Bedrock AgentCore Memory resource.</p>', 'CreateOauth2CredentialProvider' => '<p>Creates a new OAuth2 credential provider.</p>', 'CreateOnlineEvaluationConfig' => '<p> Creates an online evaluation configuration for continuous monitoring of agent performance. Online evaluation automatically samples live traffic from CloudWatch logs at specified rates and applies evaluators to assess agent quality in production. </p>', 'CreatePaymentConnector' => '<p>Creates a new payment connector for a payment manager. A payment connector integrates with a supported payment provider to enable payment processing capabilities.</p>', 'CreatePaymentCredentialProvider' => '<p>Creates a new payment credential provider for storing authentication credentials used by payment connectors to communicate with external payment providers.</p>', 'CreatePaymentManager' => '<p>Creates a new payment manager in your Amazon Web Services account. A payment manager serves as the top-level resource for managing payment processing capabilities, including payment connectors that integrate with supported payment providers.</p> <p>If you specify <code>CUSTOM_JWT</code> as the <code>authorizerType</code>, you must provide an <code>authorizerConfiguration</code>.</p>', 'CreatePolicy' => '<p>Creates a policy within the AgentCore Policy system. Policies provide real-time, deterministic control over agentic interactions with AgentCore Gateway. Using the Cedar policy language, you can define fine-grained policies that specify which interactions with Gateway tools are permitted based on input parameters and OAuth claims, ensuring agents operate within defined boundaries and business rules. The policy is validated during creation against the Cedar schema generated from the Gateway\'s tools\' input schemas, which defines the available tools, their parameters, and expected data types. This is an asynchronous operation. Use the <a href="https://docs.aws.amazon.com/bedrock-agentcore-control/latest/APIReference/API_GetPolicy.html">GetPolicy</a> operation to poll the <code>status</code> field to track completion.</p>', 'CreatePolicyEngine' => '<p>Creates a new policy engine within the AgentCore Policy system. A policy engine is a collection of policies that evaluates and authorizes agent tool calls. When associated with Gateways (each Gateway can be associated with at most one policy engine, but multiple Gateways can be associated with the same engine), the policy engine intercepts all agent requests and determines whether to allow or deny each action based on the defined policies. This is an asynchronous operation. Use the <a href="https://docs.aws.amazon.com/bedrock-agentcore-control/latest/APIReference/API_GetPolicyEngine.html">GetPolicyEngine</a> operation to poll the <code>status</code> field to track completion.</p>', 'CreateRegistry' => '<p>Creates a new registry in your Amazon Web Services account. A registry serves as a centralized catalog for organizing and managing registry records, including MCP servers, A2A agents, agent skills, and custom resource types.</p> <p>If you specify <code>CUSTOM_JWT</code> as the <code>authorizerType</code>, you must provide an <code>authorizerConfiguration</code>.</p>', 'CreateRegistryRecord' => '<p>Creates a new registry record within the specified registry. A registry record represents an individual AI resource\'s metadata in the registry. This could be an MCP server (and associated tools), A2A agent, agent skill, or a custom resource with a custom schema.</p> <p>The record is processed asynchronously and returns HTTP 202 Accepted.</p>', 'CreateWorkloadIdentity' => '<p>Creates a new workload identity.</p>', 'DeleteAgentRuntime' => '<p>Deletes an Amazon Bedrock AgentCore Runtime.</p>', 'DeleteAgentRuntimeEndpoint' => '<p>Deletes an AAgentCore Runtime endpoint.</p>', 'DeleteApiKeyCredentialProvider' => '<p>Deletes an API key credential provider.</p>', 'DeleteBrowser' => '<p>Deletes a custom browser.</p>', 'DeleteBrowserProfile' => '<p>Deletes a browser profile.</p>', 'DeleteCodeInterpreter' => '<p>Deletes a custom code interpreter.</p>', 'DeleteConfigurationBundle' => '<p>Deletes a configuration bundle and all of its versions.</p>', 'DeleteDataset' => '<p> Deletes a dataset version or an entire dataset asynchronously. If <code>datasetVersion</code> is absent, deletes all versions and the dataset record itself. If provided, deletes only that specific version. </p>', 'DeleteDatasetExamples' => '<p> Deletes specific examples by ID from DRAFT. All example IDs are validated before any deletes occur. If any ID does not exist in DRAFT, the entire batch is rejected (all-or-nothing semantics). </p>', 'DeleteEvaluator' => '<p> Deletes a custom evaluator. Builtin evaluators cannot be deleted. The evaluator must not be referenced by any active online evaluation configurations. </p>', 'DeleteGateway' => '<p>Deletes a gateway.</p>', 'DeleteGatewayRule' => '<p>Deletes a gateway rule.</p>', 'DeleteGatewayTarget' => '<p>Deletes a gateway target.</p> <p>You cannot delete a target that is in a pending authorization state (<code>CREATE_PENDING_AUTH</code>, <code>UPDATE_PENDING_AUTH</code>, or <code>SYNCHRONIZE_PENDING_AUTH</code>). Wait for the authorization to complete or fail before deleting the target.</p>', 'DeleteHarness' => '<p>Operation to delete a Harness.</p>', 'DeleteHarnessEndpoint' => '<p>Operation to delete a harness endpoint.</p>', 'DeleteMemory' => '<p>Deletes an Amazon Bedrock AgentCore Memory resource.</p>', 'DeleteOauth2CredentialProvider' => '<p>Deletes an OAuth2 credential provider.</p>', 'DeleteOnlineEvaluationConfig' => '<p> Deletes an online evaluation configuration and stops any ongoing evaluation processes associated with it. </p>', 'DeletePaymentConnector' => '<p>Deletes a payment connector.</p>', 'DeletePaymentCredentialProvider' => '<p>Deletes a payment credential provider and its associated stored credentials.</p>', 'DeletePaymentManager' => '<p>Deletes a payment manager. All payment connectors associated with the payment manager must be deleted before the payment manager can be deleted. This operation initiates the deletion process asynchronously.</p>', 'DeletePolicy' => '<p>Deletes an existing policy from the AgentCore Policy system. Once deleted, the policy can no longer be used for agent behavior control and all references to it become invalid. This is an asynchronous operation. Use the <code>GetPolicy</code> operation to poll the <code>status</code> field to track completion.</p>', 'DeletePolicyEngine' => '<p>Deletes an existing policy engine from the AgentCore Policy system. The policy engine must not have any associated policies before deletion. Once deleted, the policy engine and all its configurations become unavailable for policy management and evaluation. This is an asynchronous operation. Use the <code>GetPolicyEngine</code> operation to poll the <code>status</code> field to track completion.</p>', 'DeleteRegistry' => '<p>Deletes a registry. The registry must contain zero records before it can be deleted. This operation initiates the deletion process asynchronously.</p>', 'DeleteRegistryRecord' => '<p>Deletes a registry record. The record\'s status transitions to <code>DELETING</code> and the record is removed asynchronously.</p>', 'DeleteResourcePolicy' => '<p>Deletes the resource-based policy for a specified resource.</p> <note> <p>This feature is currently available only for AgentCore Runtime and Gateway.</p> </note>', 'DeleteWorkloadIdentity' => '<p>Deletes a workload identity.</p>', 'GetAgentRuntime' => '<p>Gets an Amazon Bedrock AgentCore Runtime.</p>', 'GetAgentRuntimeEndpoint' => '<p>Gets information about an Amazon Secure AgentEndpoint.</p>', 'GetApiKeyCredentialProvider' => '<p>Retrieves information about an API key credential provider.</p>', 'GetBrowser' => '<p>Gets information about a custom browser.</p>', 'GetBrowserProfile' => '<p>Gets information about a browser profile.</p>', 'GetCodeInterpreter' => '<p>Gets information about a custom code interpreter.</p>', 'GetConfigurationBundle' => '<p>Gets the latest version of a configuration bundle. By default, returns the latest version on the mainline branch. Use <code>GetConfigurationBundleVersion</code> to retrieve a specific historical version.</p>', 'GetConfigurationBundleVersion' => '<p>Gets a specific version of a configuration bundle by its version identifier.</p>', 'GetDataset' => '<p> Retrieves dataset metadata. Use the <code>datasetVersion</code> query parameter to retrieve a specific version\'s metadata. If absent, defaults to DRAFT. For paginated example content, use <code>ListDatasetExamples</code>. </p>', 'GetEvaluator' => '<p> Retrieves detailed information about an evaluator, including its configuration, status, and metadata. Works with both built-in and custom evaluators. </p>', 'GetGateway' => '<p>Retrieves information about a specific Gateway.</p>', 'GetGatewayRule' => '<p>Retrieves detailed information about a specific gateway rule.</p>', 'GetGatewayTarget' => '<p>Retrieves information about a specific gateway target.</p>', 'GetHarness' => '<p>Operation to get a single harness.</p>', 'GetHarnessEndpoint' => '<p>Operation to get a single harness endpoint.</p>', 'GetMemory' => '<p>Retrieve an existing Amazon Bedrock AgentCore Memory resource.</p>', 'GetOauth2CredentialProvider' => '<p>Retrieves information about an OAuth2 credential provider.</p>', 'GetOnlineEvaluationConfig' => '<p> Retrieves detailed information about an online evaluation configuration, including its rules, data sources, evaluators, and execution status. </p>', 'GetPaymentConnector' => '<p>Retrieves information about a specific payment connector.</p>', 'GetPaymentCredentialProvider' => '<p>Retrieves information about a specific payment credential provider.</p>', 'GetPaymentManager' => '<p>Retrieves information about a specific payment manager.</p>', 'GetPolicy' => '<p>Retrieves detailed information about a specific policy within the AgentCore Policy system. This operation returns the complete policy definition, metadata, and current status, allowing administrators to review and manage policy configurations.</p>', 'GetPolicyEngine' => '<p>Retrieves detailed information about a specific policy engine within the AgentCore Policy system. This operation returns the complete policy engine configuration, metadata, and current status, allowing administrators to review and manage policy engine settings.</p>', 'GetPolicyEngineSummary' => '<p>Retrieves a metadata-only summary of a specific policy engine without decrypting customer content. This lightweight read operation returns resource identifiers, status, timestamps, and the encryption key ARN, but does not include the description or status reasons. Because this operation does not require access to the customer\'s KMS key, it is suitable for resource discovery, inventory, and integration scenarios where only metadata is needed.</p>', 'GetPolicyGeneration' => '<p>Retrieves information about a policy generation request within the AgentCore Policy system. Policy generation converts natural language descriptions into Cedar policy statements using AI-powered translation, enabling non-technical users to create policies.</p>', 'GetPolicyGenerationSummary' => '<p>Retrieves a metadata-only summary of a specific policy generation request without decrypting customer content. This lightweight read operation returns resource identifiers, status, timestamps, and findings, but does not include status reasons. Because this operation does not require access to the customer\'s KMS key, it is suitable for resource discovery, inventory, and integration scenarios where only metadata is needed.</p>', 'GetPolicySummary' => '<p>Retrieves a metadata-only summary of a specific policy without decrypting customer content. This lightweight read operation returns resource identifiers, status, and timestamps, but does not include the policy definition, description, or status reasons. Because this operation does not require access to the customer\'s KMS key, it is suitable for resource discovery, inventory, and integration scenarios where only metadata is needed.</p>', 'GetRegistry' => '<p>Retrieves information about a specific registry.</p>', 'GetRegistryRecord' => '<p>Retrieves information about a specific registry record.</p>', 'GetResourcePolicy' => '<p>Retrieves the resource-based policy for a specified resource.</p> <note> <p>This feature is currently available only for AgentCore Runtime and Gateway.</p> </note>', 'GetTokenVault' => '<p>Retrieves information about a token vault.</p>', 'GetWorkloadIdentity' => '<p>Retrieves information about a workload identity.</p>', 'ListAgentRuntimeEndpoints' => '<p>Lists all endpoints for a specific Amazon Secure Agent.</p>', 'ListAgentRuntimeVersions' => '<p>Lists all versions of a specific Amazon Secure Agent.</p>', 'ListAgentRuntimes' => '<p>Lists all Amazon Secure Agents in your account.</p>', 'ListApiKeyCredentialProviders' => '<p>Lists all API key credential providers in your account.</p>', 'ListBrowserProfiles' => '<p>Lists all browser profiles in your account.</p>', 'ListBrowsers' => '<p>Lists all custom browsers in your account.</p>', 'ListCodeInterpreters' => '<p>Lists all custom code interpreters in your account.</p>', 'ListConfigurationBundleVersions' => '<p>Lists all versions of a configuration bundle, with optional filtering by branch name or creation source.</p>', 'ListConfigurationBundles' => '<p>Lists all configuration bundles in the account.</p>', 'ListDatasetExamples' => '<p> Returns paginated examples from the dataset. The server embeds the resolved version in the pagination token. Once pagination begins, all subsequent pages are pinned to that version regardless of concurrent mutations. </p>', 'ListDatasetVersions' => '<p> Lists all published versions of a dataset, sorted by version number descending (newest first). Does not include the DRAFT working copy. </p>', 'ListDatasets' => '<p> Lists all datasets in the caller\'s account, paginated. </p>', 'ListEvaluators' => '<p> Lists all available evaluators, including both builtin evaluators provided by the service and custom evaluators created by the user. </p>', 'ListGatewayRules' => '<p>Lists all rules for a gateway.</p>', 'ListGatewayTargets' => '<p>Lists all targets for a specific gateway.</p>', 'ListGateways' => '<p>Lists all gateways in the account.</p>', 'ListHarnessEndpoints' => '<p>Operation to list the endpoints of a harness.</p>', 'ListHarnessVersions' => '<p>Operation to list the versions of a Harness.</p>', 'ListHarnesses' => '<p>Operation to list harnesses.</p>', 'ListMemories' => '<p>Lists the available Amazon Bedrock AgentCore Memory resources in the current Amazon Web Services Region.</p>', 'ListOauth2CredentialProviders' => '<p>Lists all OAuth2 credential providers in your account.</p>', 'ListOnlineEvaluationConfigs' => '<p> Lists all online evaluation configurations in the account, providing summary information about each configuration\'s status and settings. </p>', 'ListPaymentConnectors' => '<p>Lists all payment connectors for a specified payment manager.</p>', 'ListPaymentCredentialProviders' => '<p>Lists all payment credential providers in the account.</p>', 'ListPaymentManagers' => '<p>Lists all payment managers in the account.</p>', 'ListPolicies' => '<p>Retrieves a list of policies within the AgentCore Policy engine. This operation supports pagination and filtering to help administrators manage and discover policies across policy engines. Results can be filtered by policy engine or resource associations.</p>', 'ListPolicyEngineSummaries' => '<p>Retrieves a paginated list of metadata-only policy engine summaries without decrypting customer content. This lightweight read operation returns resource identifiers, status, and timestamps for each policy engine, but does not include descriptions or status reasons. Because this operation does not require access to the customer\'s KMS key, it is suitable for resource discovery, inventory, and integration scenarios where only metadata is needed.</p>', 'ListPolicyEngines' => '<p>Retrieves a list of policy engines within the AgentCore Policy system. This operation supports pagination to help administrators discover and manage policy engines across their account. Each policy engine serves as a container for related policies.</p>', 'ListPolicyGenerationAssets' => '<p>Retrieves a list of generated policy assets from a policy generation request within the AgentCore Policy system. This operation returns the actual Cedar policies and related artifacts produced by the AI-powered policy generation process, allowing users to review and select from multiple generated policy options.</p>', 'ListPolicyGenerationSummaries' => '<p>Retrieves a paginated list of metadata-only policy generation summaries within a policy engine without decrypting customer content. This lightweight read operation returns resource identifiers, status, timestamps, and findings for each policy generation, but does not include status reasons. Because this operation does not require access to the customer\'s KMS key, it is suitable for resource discovery, inventory, and integration scenarios where only metadata is needed.</p>', 'ListPolicyGenerations' => '<p>Retrieves a list of policy generation requests within the AgentCore Policy system. This operation supports pagination and filtering to help track and manage AI-powered policy generation operations.</p>', 'ListPolicySummaries' => '<p>Retrieves a paginated list of metadata-only policy summaries within a policy engine without decrypting customer content. This lightweight read operation returns resource identifiers, status, and timestamps for each policy, but does not include policy definitions, descriptions, or status reasons. Because this operation does not require access to the customer\'s KMS key, it is suitable for resource discovery, inventory, and integration scenarios where only metadata is needed.</p>', 'ListRegistries' => '<p>Lists all registries in the account. You can optionally filter results by status using the <code>status</code> parameter, or by authorizer type using the <code>authorizerType</code> parameter.</p>', 'ListRegistryRecords' => '<p>Lists registry records within a registry. You can optionally filter results using the <code>name</code>, <code>status</code>, and <code>descriptorType</code> parameters. When multiple filters are specified, they are combined using AND logic.</p>', 'ListTagsForResource' => '<p>Lists the tags associated with the specified resource.</p> <note> <p>This feature is currently available only for AgentCore Runtime, Browser, Browser Profile, Code Interpreter tool, and Gateway.</p> </note>', 'ListWorkloadIdentities' => '<p>Lists all workload identities in your account.</p>', 'PutResourcePolicy' => '<p>Creates or updates a resource-based policy for a resource with the specified resourceArn.</p> <note> <p>This feature is currently available only for AgentCore Runtime and Gateway.</p> </note>', 'SetTokenVaultCMK' => '<p>Sets the customer master key (CMK) for a token vault.</p>', 'StartPolicyGeneration' => '<p>Initiates the AI-powered generation of Cedar policies from natural language descriptions within the AgentCore Policy system. This feature enables both technical and non-technical users to create policies by describing their authorization requirements in plain English, which is then automatically translated into formal Cedar policy statements. The generation process analyzes the natural language input along with the Gateway\'s tool context to produce validated policy options. Generated policy assets are automatically deleted after 7 days, so you should review and create policies from the generated assets within this timeframe. Once created, policies are permanent and not subject to this expiration. Generated policies should be reviewed and tested in log-only mode before deploying to production. Use this when you want to describe policy intent naturally rather than learning Cedar syntax, though generated policies may require refinement for complex scenarios.</p>', 'SubmitRegistryRecordForApproval' => '<p>Submits a registry record for approval. This transitions the record from <code>DRAFT</code> status to <code>PENDING_APPROVAL</code> status. If the registry has auto-approval enabled, the record is automatically approved.</p>', 'SynchronizeGatewayTargets' => '<p>Synchronizes the gateway targets by fetching the latest tool definitions from the target endpoints.</p> <p>You cannot synchronize a target that is in a pending authorization state (<code>CREATE_PENDING_AUTH</code>, <code>UPDATE_PENDING_AUTH</code>, or <code>SYNCHRONIZE_PENDING_AUTH</code>). Wait for the authorization to complete or fail before synchronizing.</p> <p>You cannot synchronize a target that has a static tool schema (<code>mcpToolSchema</code>) configured. Remove the static schema through an <code>UpdateGatewayTarget</code> call to enable dynamic tool synchronization.</p>', 'TagResource' => '<p>Associates the specified tags to a resource with the specified resourceArn. If existing tags on a resource are not specified in the request parameters, they are not changed. When a resource is deleted, the tags associated with that resource are also deleted.</p> <note> <p>This feature is currently available only for AgentCore Runtime, Browser, Browser Profile, Code Interpreter tool, and Gateway.</p> </note>', 'UntagResource' => '<p>Removes the specified tags from the specified resource.</p> <note> <p>This feature is currently available only for AgentCore Runtime, Browser, Browser Profile, Code Interpreter tool, and Gateway.</p> </note>', 'UpdateAgentRuntime' => '<p>Updates an existing Amazon Secure Agent.</p>', 'UpdateAgentRuntimeEndpoint' => '<p>Updates an existing Amazon Bedrock AgentCore Runtime endpoint.</p>', 'UpdateApiKeyCredentialProvider' => '<p>Updates an existing API key credential provider.</p>', 'UpdateConfigurationBundle' => '<p>Updates a configuration bundle by creating a new version with the specified changes. Each update creates a new version in the version history.</p>', 'UpdateDataset' => '<p> Updates a dataset\'s metadata. Synchronous operation. Only provided fields are updated; omitted fields remain unchanged. To modify dataset content, use <code>AddDatasetExamples</code>, <code>UpdateDatasetExamples</code>, or <code>DeleteDatasetExamples</code>. </p>', 'UpdateDatasetExamples' => '<p> Updates multiple existing examples in-place on DRAFT. All examples are validated against the dataset\'s schema type before any writes occur. If any example fails validation, the entire batch is rejected (all-or-nothing semantics). </p>', 'UpdateEvaluator' => '<p> Updates a custom evaluator\'s configuration, description, or evaluation level. Built-in evaluators cannot be updated. The evaluator must not be locked for modification. </p>', 'UpdateGateway' => '<p>Updates an existing gateway.</p>', 'UpdateGatewayRule' => '<p>Updates a gateway rule\'s priority, conditions, actions, or description.</p>', 'UpdateGatewayTarget' => '<p>Updates an existing gateway target.</p> <p>You cannot update a target that is in a pending authorization state (<code>CREATE_PENDING_AUTH</code>, <code>UPDATE_PENDING_AUTH</code>, or <code>SYNCHRONIZE_PENDING_AUTH</code>). Wait for the authorization to complete or fail before updating the target.</p>', 'UpdateHarness' => '<p>Operation to update a harness.</p>', 'UpdateHarnessEndpoint' => '<p>Operation to update a harness endpoint.</p>', 'UpdateMemory' => '<p>Update an Amazon Bedrock AgentCore Memory resource memory.</p>', 'UpdateOauth2CredentialProvider' => '<p>Updates an existing OAuth2 credential provider.</p>', 'UpdateOnlineEvaluationConfig' => '<p> Updates an online evaluation configuration\'s settings, including rules, data sources, evaluators, and execution status. Changes take effect immediately for ongoing evaluations. </p>', 'UpdatePaymentConnector' => '<p>Updates an existing payment connector. This operation uses PATCH semantics, so you only need to specify the fields you want to change.</p>', 'UpdatePaymentCredentialProvider' => '<p>Updates an existing payment credential provider with new authentication credentials.</p>', 'UpdatePaymentManager' => '<p>Updates an existing payment manager. This operation uses PATCH semantics, so you only need to specify the fields you want to change.</p>', 'UpdatePolicy' => '<p>Updates an existing policy within the AgentCore Policy system. This operation allows modification of the policy description and definition while maintaining the policy\'s identity. The updated policy is validated against the Cedar schema before being applied. This is an asynchronous operation. Use the <code>GetPolicy</code> operation to poll the <code>status</code> field to track completion.</p>', 'UpdatePolicyEngine' => '<p>Updates an existing policy engine within the AgentCore Policy system. This operation allows modification of the policy engine description while maintaining its identity. This is an asynchronous operation. Use the <code>GetPolicyEngine</code> operation to poll the <code>status</code> field to track completion.</p>', 'UpdateRegistry' => '<p>Updates an existing registry. This operation uses PATCH semantics, so you only need to specify the fields you want to change.</p>', 'UpdateRegistryRecord' => '<p>Updates an existing registry record. This operation uses PATCH semantics, so you only need to specify the fields you want to change. The update is processed asynchronously and returns HTTP 202 Accepted.</p>', 'UpdateRegistryRecordStatus' => '<p>Updates the status of a registry record. Use this operation to approve, reject, or deprecate a registry record.</p>', 'UpdateWorkloadIdentity' => '<p>Updates an existing workload identity.</p>', ], 'shapes' => [ 'A2aDescriptor' => [ 'base' => '<p>The Agent-to-Agent (A2A) protocol descriptor for a registry record. Contains the agent card definition as defined by the A2A protocol specification.</p>', 'refs' => [ 'Descriptors$a2a' => '<p>The Agent-to-Agent (A2A) protocol descriptor configuration. Use this when the <code>descriptorType</code> is <code>A2A</code>.</p>', 'UpdatedA2aDescriptor$optionalValue' => '<p>The updated A2A descriptor value.</p>', ], ], 'AccessDeniedException' => [ 'base' => '<p>This exception is thrown when a request is denied per access permissions</p>', 'refs' => [], ], 'Action' => [ 'base' => '<p>An action to take when a gateway rule\'s conditions are met.</p>', 'refs' => [ 'Actions$member' => NULL, ], ], 'Actions' => [ 'base' => NULL, 'refs' => [ 'CreateGatewayRuleRequest$actions' => '<p>The actions to take when the rule conditions are met. Actions can route to a specific target or apply a configuration bundle override.</p>', 'CreateGatewayRuleResponse$actions' => '<p>The actions to take when the rule conditions are met.</p>', 'GatewayRuleDetail$actions' => '<p>The actions to take when the rule conditions are met.</p>', 