L, 'refs' => [ 'StrategyConfiguration$type' => '<p>The type of override for the strategy configuration.</p>', ], ], 'PassthroughEndpoint' => [ 'base' => NULL, 'refs' => [ 'InferenceProviderTargetConfiguration$endpoint' => '<p>The HTTPS endpoint of the inference provider that the gateway forwards requests to.</p>', 'PassthroughTargetConfiguration$endpoint' => '<p>The HTTPS endpoint that the gateway forwards requests to for this passthrough target.</p>', ], ], 'PassthroughProtocolType' => [ 'base' => NULL, 'refs' => [ 'PassthroughTargetConfiguration$protocolType' => '<p>The application protocol that the passthrough target implements. This value is required for passthrough targets:</p> <ul> <li> <p> <code>MCP</code> - The Model Context Protocol.</p> </li> <li> <p> <code>A2A</code> - The Agent-to-Agent protocol.</p> </li> <li> <p> <code>INFERENCE</code> - The protocol for routing requests to a large language model (LLM) provider.</p> </li> <li> <p> <code>CUSTOM</code> - A custom application protocol.</p> </li> </ul>', ], ], 'PassthroughTargetConfiguration' => [ 'base' => '<p>The configuration for an HTTP passthrough target. A passthrough target forwards requests directly to an external HTTP endpoint.</p>', 'refs' => [ 'HttpTargetConfiguration$passthrough' => '<p>The passthrough configuration for the HTTP target. A passthrough target forwards requests directly to an external HTTP endpoint.</p>', ], ], 'PaymentConnectorId' => [ 'base' => NULL, 'refs' => [ 'CreatePaymentConnectorResponse$paymentConnectorId' => '<p>The unique identifier of the created payment connector.</p>', 'DeletePaymentConnectorRequest$paymentConnectorId' => '<p>The unique identifier of the payment connector to delete.</p>', 'DeletePaymentConnectorResponse$paymentConnectorId' => '<p>The unique identifier of the deleted payment connector.</p>', 'GetPaymentConnectorRequest$paymentConnectorId' => '<p>The unique identifier of the payment connector to retrieve.</p>', 'GetPaymentConnectorResponse$paymentConnectorId' => '<p>The unique identifier of the payment connector.</p>', 'PaymentConnectorSummary$paymentConnectorId' => '<p>The unique identifier of the payment connector.</p>', 'UpdatePaymentConnectorRequest$paymentConnectorId' => '<p>The unique identifier of the payment connector to update.</p>', 'UpdatePaymentConnectorResponse$paymentConnectorId' => '<p>The unique identifier of the updated payment connector.</p>', ], ], 'PaymentConnectorName' => [ 'base' => NULL, 'refs' => [ 'CreatePaymentConnectorRequest$name' => '<p>The name of the payment connector.</p>', 'CreatePaymentConnectorResponse$name' => '<p>The name of the created payment connector.</p>', 'GetPaymentConnectorResponse$name' => '<p>The name of the payment connector.</p>', 'PaymentConnectorSummary$name' => '<p>The name of the payment connector.</p>', 'UpdatePaymentConnectorResponse$name' => '<p>The name of the updated payment connector.</p>', ], ], 'PaymentConnectorStatus' => [ 'base' => NULL, 'refs' => [ 'CreatePaymentConnectorResponse$status' => '<p>The current status of the payment connector. Possible values include <code>CREATING</code>, <code>READY</code>, <code>UPDATING</code>, <code>DELETING</code>, <code>CREATE_FAILED</code>, <code>UPDATE_FAILED</code>, and <code>DELETE_FAILED</code>.</p>', 'DeletePaymentConnectorResponse$status' => '<p>The current status of the payment connector, set to <code>DELETING</code> when deletion is initiated. Possible values include <code>CREATING</code>, <code>READY</code>, <code>UPDATING</code>, <code>DELETING</code>, <code>CREATE_FAILED</code>, <code>UPDATE_FAILED</code>, and <code>DELETE_FAILED</code>.</p>', 'GetPaymentConnectorResponse$status' => '<p>The current status of the payment connector. Possible values include <code>CREATING</code>, <code>READY</code>, <code>UPDATING</code>, <code>DELETING</code>, <code>CREATE_FAILED</code>, <code>UPDATE_FAILED</code>, and <code>DELETE_FAILED</code>.</p>', 'PaymentConnectorSummary$status' => '<p>The current status of the payment connector. Possible values include <code>CREATING</code>, <code>READY</code>, <code>UPDATING</code>, <code>DELETING</code>, <code>CREATE_FAILED</code>, <code>UPDATE_FAILED</code>, and <code>DELETE_FAILED</code>.</p>', 'UpdatePaymentConnectorResponse$status' => '<p>The current status of the updated payment connector. Possible values include <code>CREATING</code>, <code>READY</code>, <code>UPDATING</code>, <code>DELETING</code>, <code>CREATE_FAILED</code>, <code>UPDATE_FAILED</code>, and <code>DELETE_FAILED</code>.</p>', ], ], 'PaymentConnectorSummaries' => [ 'base' => NULL, 'refs' => [ 'ListPaymentConnectorsResponse$paymentConnectors' => '<p>The list of payment connector summaries. For details about the fields in each summary, see the <code>PaymentConnectorSummary</code> data type.</p>', ], ], 'PaymentConnectorSummary' => [ 'base' => '<p>Contains summary information about a payment connector.</p>', 'refs' => [ 'PaymentConnectorSummaries$member' => NULL, ], ], 'PaymentConnectorType' => [ 'base' => NULL, 'refs' => [ 'CreatePaymentConnectorRequest$type' => '<p>The type of payment connector, which determines the payment provider integration.</p>', 'CreatePaymentConnectorResponse$type' => '<p>The type of the created payment connector.</p>', 'GetPaymentConnectorResponse$type' => '<p>The type of the payment connector, which determines the payment provider integration.</p>', 'PaymentConnectorSummary$type' => '<p>The type of the payment connector, which determines the payment provider integration.</p>', 'UpdatePaymentConnectorRequest$type' => '<p>The updated type of the payment connector.</p>', 'UpdatePaymentConnectorResponse$type' => '<p>The type of the updated payment connector.</p>', ], ], 'PaymentCredentialProviderArn' => [ 'base' => NULL, 'refs' => [ 'PaymentCredentialProviderConfiguration$credentialProviderArn' => '<p>The Amazon Resource Name (ARN) of the credential provider that stores the authentication credentials for the payment provider.</p>', ], ], 'PaymentCre